('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:329cebbb', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "Add: \\( (3x^2 + 2x - 5) + (x^2 - 4x + 1) \\).", "options": ["\\( 4x^2 - 2x - 4 \\)", "\\( 4x^2 + 6x - 4 \\)", "\\( 4x^2 - 2x - 5 \\)", "\\( 4x^4 - 2x - 4 \\)"]}'::jsonb, '{"answer": 0, "explain": "Collect like terms: \\( (3+1)x^2 + (2-4)x + (-5+1) = 4x^2 - 2x - 4 \\). Powers are not added when combining terms."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:8363591d', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "Subtract: \\( (5x^2 - 3x + 2) - (2x^2 + x - 4) \\).", "options": ["\\( 3x^2 - 4x + 6 \\)", "\\( 3x^2 - 4x - 2 \\)", "\\( 3x^2 - 2x - 2 \\)", "\\( 3x^2 - 2x + 6 \\)"]}'::jsonb, '{"answer": 0, "explain": "Change every sign in the second bracket: \\( 5x^2 - 3x + 2 - 2x^2 - x + 4 = 3x^2 - 4x + 6 \\). Note \\( 2 - (-4) = 6 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:c2b2a8a6', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "Expand: \\( (x + 4)(x - 2) \\).", "options": ["\\( x^2 + 2x - 8 \\)", "\\( x^2 + 6x - 8 \\)", "\\( x^2 - 8 \\)", "\\( x^2 + 2x + 8 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x^2 - 2x + 4x - 8 = x^2 + 2x - 8 \\). The middle term is \\( -2x + 4x = 2x \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:28bc13eb', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "Expand: \\( (x - 3)(x^2 + 2x - 1) \\).", "options": ["\\( x^3 - x^2 - 7x + 3 \\)", "\\( x^3 + 5x^2 - 7x + 3 \\)", "\\( x^3 - x^2 - 7x - 3 \\)", "\\( x^3 - x^2 + 5x + 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x(x^2+2x-1) = x^3+2x^2-x \\) and \\( -3(x^2+2x-1) = -3x^2-6x+3 \\); adding gives \\( x^3 - x^2 - 7x + 3 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:bd5f55cb', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "What is the degree of the product \\( (2x^3 - 5)(x^2 + x) \\)?", "options": ["5", "6", "3", "2"]}'::jsonb, '{"answer": 0, "explain": "The degree of a product is the sum of the degrees: \\( 3 + 2 = 5 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:a05042cc', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "Divide \\( x^3 - 3x^2 - x - 3 \\) by \\( x - 3 \\). What is the quotient?", "options": ["\\( x^2 - 1 \\)", "\\( x^2 - x - 4 \\)", "\\( x^2 - 6 \\)", "\\( x^2 + 1 \\)"]}'::jsonb, '{"answer": 0, "explain": "After the first step the working has no \\( x^2 \\) term left, so the quotient''s \\( x \\) coefficient is \\( 0 \\): quotient \\( = x^2 - 1 \\), remainder \\( -6 \\). Check: \\( (x-3)(x^2-1) - 6 = x^3 - 3x^2 - x - 3 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:5a9b3b58', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "Dividing \\( x^3 - 3x^2 - x - 3 \\) by \\( x - 3 \\) leaves what remainder?", "options": ["\\( -6 \\)", "\\( 6 \\)", "\\( \\frac{-6}{x-3} \\)", "\\( 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "The remainder is the constant left at the end, \\( -6 \\). \\( \\frac{-6}{x-3} \\) is the fractional part of the full answer, not the remainder."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:62f698a6', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "When you divide \\( x^3 + 4x^2 + x + 2 \\) by \\( x + 2 \\), what is the first term of the quotient?", "options": ["\\( x^2 \\)", "\\( x^3 \\)", "\\( x \\)", "\\( 2x^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "Divide the leading terms: \\( x^3 \\div x = x^2 \\). That is always the first step of polynomial long division."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:a5f519fb', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "A polynomial is divided by \\( x - a \\) and the remainder is \\( 0 \\). What does this tell you?", "options": ["\\( x - a \\) is a factor of the polynomial", "The polynomial is linear", "The quotient is also \\( 0 \\)", "You made an arithmetic mistake"]}'::jsonb, '{"answer": 0, "explain": "A remainder of \\( 0 \\) means the division is exact, so \\( x - a \\) divides the polynomial exactly — it is a factor."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:ea59269b', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "It is given that \\( x^3 + 4x^2 + x - 6 = (x + 2)(x^2 + ax + b) \\). Find \\( a \\).", "options": ["\\( 2 \\)", "\\( 4 \\)", "\\( -2 \\)", "\\( 6 \\)"]}'::jsonb, '{"answer": 0, "explain": "Comparing \\( x^2 \\) terms in the expansion \\( (x+2)(x^2+ax+b) = x^3 + (a+2)x^2 + \\dots \\): \\( a + 2 = 4 \\Rightarrow a = 2 \\) (the quotient is \\( x^2 + 2x - 3 \\))."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:mcq:1ecca96e', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'mcq', 'mcq', 1, '{"question": "To divide \\( 2x^3 - 5x + 1 \\) by \\( x - 1 \\), what should you do about the missing \\( x^2 \\) term?", "options": ["Write it in as \\( 0x^2 \\) to keep the columns lined up", "Ignore it — a missing term has no effect", "Add it to the constant term", "Move the \\( -5x \\) up into its place"]}'::jsonb, '{"answer": 0, "explain": "Insert a \\( 0x^2 \\) placeholder so every power has a column; otherwise the subtractions misalign and errors creep in."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tf:baa06ddb', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tf', 'tf', 1, '{"question": "The degree of a polynomial is the highest power of its variable."}'::jsonb, '{"answer": true, "explain": "Correct — e.g. \\( 4x^5 - 2x^2 + 7 \\) has degree \\( 5 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tf:8a398730', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tf', 'tf', 1, '{"question": "\\( (x + 2)(x - 2) = x^2 - 4 \\)."}'::jsonb, '{"answer": true, "explain": "This is the difference of two squares: \\( (x+a)(x-a) = x^2 - a^2 \\), here \\( a = 2 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tf:7dff351d', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tf', 'tf', 1, '{"question": "When subtracting polynomials you only change the sign of the first term of the second bracket."}'::jsonb, '{"answer": false, "explain": "You must change the sign of EVERY term in the second bracket, not just the first."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tf:58ed857d', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tf', 'tf', 1, '{"question": "The remainder from a polynomial division can be written as a fraction and still counts as the remainder."}'::jsonb, '{"answer": false, "explain": "The remainder is a number (of lower degree than the divisor). \\( \\frac{14}{x+3} \\) is the fractional part of the answer, not the remainder \\( 14 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tf:a3d0f1c7', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tf', 'tf', 1, '{"question": "In \\( x^3 + 2x^2 - 5x + 8 = (x + 3)(x^2 - x - 2) + 14 \\), the number \\( 14 \\) is the remainder."}'::jsonb, '{"answer": true, "explain": "Written as (divisor)(quotient) + remainder, the constant \\( 14 \\) is exactly the remainder."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tf:9daa99c7', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tf', 'tf', 1, '{"question": "Dividing a degree-3 polynomial by a degree-1 polynomial gives a quotient of degree 2."}'::jsonb, '{"answer": true, "explain": "Degrees subtract: \\( 3 - 1 = 2 \\), so the quotient is a quadratic."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tf:faffe52b', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tf', 'tf', 1, '{"question": "If a polynomial divides by \\( x - a \\) with remainder \\( 0 \\), then \\( x - a \\) is a factor."}'::jsonb, '{"answer": true, "explain": "Remainder \\( 0 \\) means the division is exact, which is the definition of a factor."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tf:d4ffaa02', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tf', 'tf', 1, '{"question": "Adding \\( x^2 \\) and \\( x^3 \\) gives \\( x^5 \\)."}'::jsonb, '{"answer": false, "explain": "They are unlike terms, so they stay as \\( x^3 + x^2 \\). You only add indices when you MULTIPLY: \\( x^2 \\times x^3 = x^5 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:learn:8689eb07', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'learn', 'mcq', 1, '{"readingTitle": "What is a polynomial, and what do we call its parts?", "reading": "<p>A <strong>polynomial</strong> is a sum of terms of the form \\( a x^n \\), where the powers \\( n \\) are whole numbers \\( (0, 1, 2, 3, \\dots) \\). For example \\( 2x^3 - 5x^2 + x - 4 \\) is a polynomial; \\( \\dfrac{1}{x} \\) and \\( \\sqrt{x} \\) are <em>not</em> (their powers are \\( -1 \\) and \\( \\tfrac{1}{2} \\)).</p>\n            <ul>\n              <li>The <strong>degree</strong> is the highest power of \\( x \\). \\( 2x^3 - 5x^2 + x - 4 \\) has degree 3 (a <em>cubic</em>); degree 2 is a <em>quadratic</em>, degree 1 is <em>linear</em>.</li>\n              <li>A <strong>coefficient</strong> is the number multiplying a power of \\( x \\) — here the coefficient of \\( x^2 \\) is \\( -5 \\).</li>\n              <li>The number on its own (\\( -4 \\)) is the <strong>constant term</strong>.</li>\n              <li>Write polynomials in <strong>descending order</strong> — highest power first — so the arithmetic lines up neatly.</li>\n              <li>Only <strong>like terms</strong> (same power of \\( x \\)) can be combined: \\( 3x^2 \\) and \\( 5x^2 \\) add to \\( 8x^2 \\), but \\( 3x^2 \\) and \\( 5x \\) stay apart.</li>\n            </ul>", "question": "What is the degree of \\( 4x^5 - 2x^2 + 7 \\)?", "options": ["5", "4", "2", "7"]}'::jsonb, '{"answer": 0, "explain": "The degree is the highest power of \\( x \\), which is \\( 5 \\). The constant \\( 7 \\) has power \\( 0 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:learn:2928b337', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'learn', 'mcq', 1, '{"readingTitle": "How do you add and subtract polynomials?", "reading": "<p>Collect <strong>like terms</strong> — line up equal powers of \\( x \\) and combine their coefficients. For <strong>subtraction</strong>, the single biggest trap is the minus sign: it must be applied to <em>every</em> term in the second bracket.</p>\n            <p><strong>Worked example — \\( (5x^2 - 3x + 2) - (2x^2 + x - 4) \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Change the sign of every term in the second bracket: \\( +2x^2 \\to -2x^2 \\), \\( +x \\to -x \\), \\( -4 \\to +4 \\).</td></tr>\n              <tr><td>2. So it becomes \\( 5x^2 - 3x + 2 - 2x^2 - x + 4 \\).</td></tr>\n              <tr><td>3. Combine like terms: \\( (5-2)x^2 + (-3-1)x + (2+4) \\).</td></tr>\n              <tr><td>4. Result: \\[ 3x^2 - 4x + 6. \\]</td></tr>\n            </table>\n            <p>Notice the last term: \\( 2 - (-4) = 2 + 4 = 6 \\). Missing the double negative here is the most common slip.</p>", "question": "\\( (3x^2 - x + 2) - (x^2 + 4x - 5) = ? \\)", "options": ["\\( 2x^2 - 5x + 7 \\)", "\\( 2x^2 + 3x + 7 \\)", "\\( 2x^2 - 5x - 3 \\)", "\\( 4x^2 - 5x + 7 \\)"]}'::jsonb, '{"answer": 0, "explain": "Change every sign in the second bracket: \\( 3x^2 - x + 2 - x^2 - 4x + 5 = 2x^2 - 5x + 7 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:learn:f3143cfb', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'learn', 'mcq', 1, '{"readingTitle": "How do you multiply polynomials?", "reading": "<p>Multiply <strong>every</strong> term in the first bracket by every term in the second, then collect like terms. The degree of the product is the sum of the two degrees (a cubic times a quadratic gives degree \\( 3+2 = 5 \\)).</p>\n            <p><strong>Worked example — \\( (x - 3)(x^2 + 2x - 1) \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( x \\times (x^2 + 2x - 1) = x^3 + 2x^2 - x \\).</td></tr>\n              <tr><td>2. \\( -3 \\times (x^2 + 2x - 1) = -3x^2 - 6x + 3 \\).</td></tr>\n              <tr><td>3. Add the two rows, lining up like terms: \\( x^3 + (2-3)x^2 + (-1-6)x + 3 \\).</td></tr>\n              <tr><td>4. Result: \\[ x^3 - x^2 - 7x + 3. \\]</td></tr>\n            </table>\n            <p>A useful special case to recognise instantly is the <strong>difference of two squares</strong>: \\( (x+a)(x-a) = x^2 - a^2 \\).</p>", "question": "\\( (x - 5)(x + 2) = ? \\)", "options": ["\\( x^2 - 3x - 10 \\)", "\\( x^2 + 7x - 10 \\)", "\\( x^2 - 3x + 10 \\)", "\\( x^2 - 10 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x^2 + 2x - 5x - 10 = x^2 - 3x - 10 \\). The middle term comes from \\( 2x - 5x \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:learn:9cd4d90f', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'learn', 'mcq', 1, '{"readingTitle": "How do you divide polynomials by long division?", "reading": "<p><strong>Polynomial (algebraic) long division</strong> works exactly like the long division of numbers. At each step you divide the leading terms, multiply back, and subtract to get a new, smaller polynomial. You stop when what is left has a <em>lower degree than the divisor</em> — that leftover is the <strong>remainder</strong>, and the terms you built up on top form the <strong>quotient</strong>.</p>\n            <p><strong>Worked example — divide \\( x^3 + 2x^2 - 5x + 8 \\) by \\( x + 3 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( x^3 \\div x = x^2 \\). Multiply: \\( x^2(x+3) = x^3 + 3x^2 \\). Subtract: \\( (x^3 + 2x^2) - (x^3 + 3x^2) = -x^2 \\). Bring down \\( -5x \\).</td></tr>\n              <tr><td>2. \\( -x^2 \\div x = -x \\). Multiply: \\( -x(x+3) = -x^2 - 3x \\). Subtract: \\( (-x^2 - 5x) - (-x^2 - 3x) = -2x \\). Bring down \\( +8 \\).</td></tr>\n              <tr><td>3. \\( -2x \\div x = -2 \\). Multiply: \\( -2(x+3) = -2x - 6 \\). Subtract: \\( (-2x + 8) - (-2x - 6) = 14 \\).</td></tr>\n              <tr><td>4. Nothing is left to bring down and \\( 14 \\) has lower degree than \\( x+3 \\), so we stop.</td></tr>\n            </table>\n            <p>So the <strong>quotient is \\( x^2 - x - 2 \\)</strong> and the <strong>remainder is \\( 14 \\)</strong>. In one line: \\[ x^3 + 2x^2 - 5x + 8 = (x+3)(x^2 - x - 2) + 14. \\] Check by expanding the right-hand side — it returns the original. If a power is missing from the dividend (say no \\( x^2 \\) term), write it in as \\( 0x^2 \\) so your columns stay lined up.</p>", "question": "When \\( 2x^3 - x^2 - 7x + 6 \\) is divided by \\( x - 1 \\), what is the remainder?", "options": ["\\( 0 \\)", "\\( 6 \\)", "\\( -6 \\)", "\\( 2 \\)"]}'::jsonb, '{"answer": 0, "explain": "The division is exact: \\( 2x^3 - x^2 - 7x + 6 = (x-1)(2x^2 + x - 6) \\), so the remainder is \\( 0 \\) — which means \\( x - 1 \\) is a factor."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:learn:67246075', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'learn', 'mcq', 1, '{"readingTitle": "How do you divide by equating coefficients instead?", "reading": "<p>There is a neat alternative to the long-division layout: write down the answer in the form <em>dividend</em> \\( = \\) (<em>divisor</em>)(<em>quotient</em>) \\( + \\) <em>remainder</em> with unknown letters, then <strong>equate coefficients</strong> to pin the letters down. For a cubic divided by a linear divisor the quotient is a quadratic \\( x^2 + bx + c \\) and the remainder is a single number \\( d \\).</p>\n            <p><strong>Worked example — same division, \\( x^3 + 2x^2 - 5x + 8 \\) by \\( x + 3 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Write \\( x^3 + 2x^2 - 5x + 8 = (x+3)(x^2 + bx + c) + d \\).</td></tr>\n              <tr><td>2. Expand the right: \\( x^3 + (b+3)x^2 + (c+3b)x + (3c + d) \\).</td></tr>\n              <tr><td>3. Compare \\( x^2 \\): \\( b + 3 = 2 \\Rightarrow b = -1 \\). Compare \\( x \\): \\( c + 3b = -5 \\Rightarrow c = -2 \\).</td></tr>\n              <tr><td>4. Compare constants: \\( 3c + d = 8 \\Rightarrow -6 + d = 8 \\Rightarrow d = 14 \\).</td></tr>\n            </table>\n            <p>This gives quotient \\( x^2 - x - 2 \\) and remainder \\( 14 \\) — exactly as long division did. Use whichever method you prefer, but be ready to <strong>use long division when a question specifically asks for it</strong>.</p>", "question": "In \\( x^3 + 2x^2 - 5x + 8 = (x+3)(x^2 + bx + c) + d \\), what is \\( b \\)?", "options": ["\\( -1 \\)", "\\( 2 \\)", "\\( -2 \\)", "\\( 1 \\)"]}'::jsonb, '{"answer": 0, "explain": "Comparing the \\( x^2 \\) coefficients: \\( b + 3 = 2 \\), so \\( b = -1 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:learn:2a81fabc', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'learn', 'mcq', 1, '{"readingTitle": "How should you state the quotient and the remainder?", "reading": "<p>This is the mark that examiners report is most often thrown away. After a correct division you must <strong>state the quotient AND the remainder, both clearly labelled</strong>. Two traps to avoid:</p>\n            <ul>\n              <li><strong>Not identifying the quotient.</strong> Doing the working but never writing \"Quotient = …\" leaves the final mark unearned. If the answer box says <em>Quotient =</em> and <em>Remainder =</em>, fill in both.</li>\n              <li><strong>Giving the remainder as a fraction.</strong> The remainder is a <em>number</em> (more generally, a polynomial of lower degree than the divisor). Dividing \\( x^3 + 2x^2 - 5x + 8 \\) by \\( x+3 \\) can be written \\[ x^2 - x - 2 + \\frac{14}{x+3}, \\] but the <strong>remainder is \\( 14 \\)</strong>, not \\( \\frac{14}{x+3} \\).</li>\n            </ul>\n            <p>A remainder of \\( 0 \\) is special: it means the divisor is a <strong>factor</strong>, which links straight to the factor theorem in the next lesson.</p>", "question": "The remainder when a cubic is divided by \\( x - a \\) is always:", "options": ["a constant (a single number)", "a linear expression in \\( x \\)", "a fraction with \\( x - a \\) on the bottom", "equal to zero"]}'::jsonb, '{"answer": 0, "explain": "The remainder must have lower degree than the divisor \\( x - a \\) (degree 1), so it is a degree-0 constant. It is only ever \\( 0 \\) when \\( x - a \\) is a factor."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:misc:05a034a8', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( (4x^2 - 2x + 3) - (x^2 - 5x + 1) = 3x^2 - 7x + 2 \\)</p><p><strong>✅ The correct idea:</strong> The minus applies to EVERY term in the second bracket. A weak answer only negates the first term; a strong answer writes \\( 4x^2 - 2x + 3 - x^2 + 5x - 1 = 3x^2 + 3x + 2 \\).</p>", "question": "\\( (4x^2 - 2x + 3) - (x^2 - 5x + 1) = ? \\)", "options": ["\\( 3x^2 + 3x + 2 \\)", "\\( 3x^2 - 7x + 2 \\)", "\\( 3x^2 + 3x + 4 \\)", "\\( 3x^2 - 7x + 4 \\)"]}'::jsonb, '{"answer": 0, "explain": "Negate all three: \\( -x^2 + 5x - 1 \\), then collect: \\( 3x^2 + 3x + 2 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:misc:91881b70', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The remainder when \\( x^3 - 3x^2 - x - 3 \\) is divided by \\( x - 3 \\) is \\( \\frac{-6}{x-3} \\)</p><p><strong>✅ The correct idea:</strong> The remainder is the constant \\( -6 \\). A weak answer leaves it as a fraction; a strong answer states ''Remainder \\( = -6 \\)''. The \\( \\frac{-6}{x-3} \\) is only the fractional part of the full quotient-plus-fraction form.</p>", "question": "What is the remainder here?", "options": ["\\( -6 \\)", "\\( \\frac{-6}{x-3} \\)", "\\( 6 \\)", "\\( x^2 - 1 \\)"]}'::jsonb, '{"answer": 0, "explain": "A remainder is a number of lower degree than the divisor — here \\( -6 \\)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:misc:f991ab00', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Doing the long division correctly but writing no ''Quotient ='' or ''Remainder ='' answer</p><p><strong>✅ The correct idea:</strong> The final mark is for IDENTIFYING both results. A weak answer stops after the working; a strong answer states the quotient AND the remainder explicitly, filling in both answer lines.</p>", "question": "After a correct division you must always:", "options": ["State the quotient AND the remainder clearly", "State only the quotient", "State only the remainder", "Leave the examiner to read your working"]}'::jsonb, '{"answer": 0, "explain": "The 2023 examiners noted many lost the last mark by not identifying the quotient (or by giving the remainder as a fraction)."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:misc:20293bb1', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Dividing \\( 2x^3 - 5x + 1 \\) by \\( x - 1 \\) without a place for the missing \\( x^2 \\) term</p><p><strong>✅ The correct idea:</strong> Insert a \\( 0x^2 \\) placeholder. A weak answer mis-aligns the columns and makes subtraction slips; a strong answer writes \\( 2x^3 + 0x^2 - 5x + 1 \\) so every power lines up.</p>", "question": "How do you handle a missing \\( x^2 \\) term in the dividend?", "options": ["Write it as \\( 0x^2 \\) to keep columns aligned", "Skip that column entirely", "Add it to the \\( -5x \\)", "Move the constant up"]}'::jsonb, '{"answer": 0, "explain": "A \\( 0x^2 \\) placeholder keeps the long-division columns aligned."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:misc:377d2a45', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( x^2 + x^3 = x^5 \\)</p><p><strong>✅ The correct idea:</strong> These are unlike terms and cannot be combined; the answer is just \\( x^3 + x^2 \\). A weak answer adds the indices; a strong answer only adds indices when MULTIPLYING, e.g. \\( x^2 \\times x^3 = x^5 \\).</p>", "question": "Simplify \\( x^2 + x^3 \\).", "options": ["\\( x^3 + x^2 \\)", "\\( x^5 \\)", "\\( 2x^5 \\)", "\\( x^6 \\)"]}'::jsonb, '{"answer": 0, "explain": "Unlike terms stay separate; indices add only under multiplication."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tips:d5ad3f77', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tips', 'mcq', 1, '{"readingTitle": "explain — State the quotient AND the remainder", "reading": "<p>The 2023 examiners reported that candidates who divided correctly still lost the final mark by <strong>not identifying the quotient</strong>, or by <strong>giving the remainder as a fraction</strong>.</p><p><strong>0 marks lost:</strong> a page of correct working but no stated answer, or \"remainder \\( = \\frac{-6}{x-3} \\)\".</p><p><strong>Full marks:</strong> \"Quotient \\( = x^2 + 2x + 3 \\), Remainder \\( = -6 \\)\" — both labelled, the remainder a number.</p>", "question": "How do you secure the final mark on a long-division question?", "options": ["Label both the quotient and the remainder (a number)", "Show working only", "Give the remainder as a fraction", "Give only the quotient"]}'::jsonb, '{"answer": 0, "explain": "Both results must be stated, and the remainder must be a number, not a fraction."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tips:fe119cf2', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tips', 'mcq', 1, '{"readingTitle": "tip — Show every step (method marks)", "reading": "<p>On a \"use long division\" question the method mark (M1) needs your working to be <strong>visible</strong>: the \\( x^2 \\) term of the quotient and the \\( x^3 + x^2 \\) line of the multiplication must be seen. Write each subtraction on its own line so a single slip costs one mark, not all three.</p>", "question": "Why write out each subtraction line in long division?", "options": ["So the method mark is earned even if a later step slips", "To use more paper", "It is optional decoration", "To avoid using a calculator"]}'::jsonb, '{"answer": 0, "explain": "Visible correct steps earn the M mark independently of the final answer."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:tips:d02e89e2', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Use long division'' means show that method", "reading": "<p>If a question says <em>\"use long division\"</em>, the equate-coefficients shortcut may not earn the method mark even with the right answer. Match the method the command word names. When no method is specified, use whichever you are faster and safer with.</p>", "question": "A question says ''use long division''. You should:", "options": ["Carry out and show the long-division method", "Use equating coefficients instead", "Just write the answer", "Use a calculator to factorise"]}'::jsonb, '{"answer": 0, "explain": "Follow the named method so the method marks are available to you."}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:fib:3ad7da62', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'fib', 'fib', 1, '{"question": "A polynomial written with its powers going from highest to lowest is in ___B1___ order.", "blankOptions": {"B1": ["constant", "descending", "coefficient", "remainder"]}}'::jsonb, '{"blanks": {"B1": "descending"}}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:fib:15907f12', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'fib', 'fib', 2, '{"question": "The ___B1___ of a polynomial is the highest power of the variable, and the number multiplying a power of \\( x \\) is its ___B2___.", "blankOptions": {"B1": ["degree", "ascending", "placeholder", "constant"], "B2": ["coefficient", "constant", "term", "zero"]}}'::jsonb, '{"blanks": {"B1": "degree", "B2": "coefficient"}}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:fib:46a7d7cb', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'fib', 'fib', 1, '{"question": "To subtract one polynomial from another you must change the ___B1___ of every term in the second bracket.", "blankOptions": {"B1": ["sign", "term", "degree", "coefficient"]}}'::jsonb, '{"blanks": {"B1": "sign"}}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:fib:6cf274ff', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'fib', 'fib', 2, '{"question": "In long division the expression built up on top is the ___B1___ and the value left over at the end is the ___B2___.", "blankOptions": {"B1": ["quotient", "degree", "descending", "ascending"], "B2": ["zero", "14", "remainder", "placeholder"]}}'::jsonb, '{"blanks": {"B1": "quotient", "B2": "remainder"}}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:fib:305d3af3', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'fib', 'fib', 1, '{"question": "When \\( x^3 + 2x^2 - 5x + 8 \\) is divided by \\( x + 3 \\), the quotient is \\( x^2 - x - 2 \\) and the remainder is ___B1___.", "blankOptions": {"B1": ["14", "factor", "degree", "coefficient"]}}'::jsonb, '{"blanks": {"B1": "14"}}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:fib:a3f4f303', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'fib', 'fib', 1, '{"question": "When a polynomial is divided by \\( x - a \\) and the remainder is ___B1___, then \\( x - a \\) is a factor.", "blankOptions": {"B1": ["constant", "quotient", "zero", "remainder"]}}'::jsonb, '{"blanks": {"B1": "zero"}}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:fib:6f5e07e3', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'fib', 'fib', 1, '{"question": "When dividing, insert a ___B1___ (a term with coefficient 0) for any missing power so the columns stay lined up.", "blankOptions": {"B1": ["placeholder", "sign", "ascending", "term"]}}'::jsonb, '{"blanks": {"B1": "placeholder"}}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:match:a59d1515', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Degree of a polynomial”?", "options": ["\\( 3x^2 + 2x + 3 \\)", "The result of the division (the part on top)", "\\( 3x^2 + 3x \\)", "The highest power of the variable"]}'::jsonb, '{"answer": 3, "explain": "“Degree of a polynomial” means: The highest power of the variable"}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:match:92717024', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Coefficient”?", "options": ["\\( 5 \\)", "The number multiplying a power of \\( x \\)", "\\( 3x^2 + 2x + 3 \\)", "\\( x - a \\) is a factor"]}'::jsonb, '{"answer": 1, "explain": "“Coefficient” means: The number multiplying a power of \\( x \\)"}'::jsonb),
