('additional-maths:2-1-polynomial-arithmetic-and-division:match:c655c7e9', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Remainder”?", "options": ["What is left over, of lower degree than the divisor", "\\( 3x^2 + 2x + 3 \\)", "\\( 5 \\)", "The highest power of the variable"]}'::jsonb, '{"answer": 0, "explain": "“Remainder” means: What is left over, of lower degree than the divisor"}'::jsonb),
