('additional-maths:2-1-polynomial-arithmetic-and-division:match:a49177a9', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( (x + 3)(x - 3) \\)”?", "options": ["What is left over, of lower degree than the divisor", "\\( 5 \\)", "\\( x^3 + 3x^2 + 5x + 3 \\)", "\\( x^2 - 9 \\)"]}'::jsonb, '{"answer": 3, "explain": "“\\( (x + 3)(x - 3) \\)” means: \\( x^2 - 9 \\)"}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:match:076c18e1', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( (x + 1)(x^2 + 2x + 3) \\)”?", "options": ["\\( 3x^2 + 2x + 3 \\)", "\\( x^3 + 3x^2 + 5x + 3 \\)", "The polynomial you are dividing by", "\\( 5 \\)"]}'::jsonb, '{"answer": 1, "explain": "“\\( (x + 1)(x^2 + 2x + 3) \\)” means: \\( x^3 + 3x^2 + 5x + 3 \\)"}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:match:c32bed80', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( (2x^2 - x + 4) + (x^2 + 3x - 1) \\)”?", "options": ["\\( 5 \\)", "\\( x^3 + 3x^2 + 5x + 3 \\)", "The highest power of the variable", "\\( 3x^2 + 2x + 3 \\)"]}'::jsonb, '{"answer": 3, "explain": "“\\( (2x^2 - x + 4) + (x^2 + 3x - 1) \\)” means: \\( 3x^2 + 2x + 3 \\)"}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:match:c4bb88fc', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( (5x^2 + 2x) - (2x^2 - x) \\)”?", "options": ["The number multiplying a power of \\( x \\)", "\\( 5 \\)", "\\( 3x^2 + 2x + 3 \\)", "\\( 3x^2 + 3x \\)"]}'::jsonb, '{"answer": 3, "explain": "“\\( (5x^2 + 2x) - (2x^2 - x) \\)” means: \\( 3x^2 + 3x \\)"}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:match:aa3a19a9', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Remainder \\( 0 \\) on dividing by \\( x - a \\)”?", "options": ["\\( x - a \\) is a factor", "What is left over, of lower degree than the divisor", "The number multiplying a power of \\( x \\)", "The highest power of the variable"]}'::jsonb, '{"answer": 0, "explain": "“Remainder \\( 0 \\) on dividing by \\( x - a \\)” means: \\( x - a \\) is a factor"}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:match:a040a8d7', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Descending order”?", "options": ["\\( 5 \\)", "The highest power of the variable", "\\( 3x^2 + 2x + 3 \\)", "Powers written from highest to lowest"]}'::jsonb, '{"answer": 3, "explain": "“Descending order” means: Powers written from highest to lowest"}'::jsonb),
('additional-maths:2-1-polynomial-arithmetic-and-division:match:d54d8a35', 'additional-maths', 'additional-maths:2-1-polynomial-arithmetic-and-division', '2.1 Polynomial Arithmetic and Division', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Degree of \\( (x^2 + 1)(x^3 - x) \\)”?", "options": ["The number multiplying a power of \\( x \\)", "The highest power of the variable", "\\( x - a \\) is a factor", "\\( 5 \\)"]}'::jsonb, '{"answer": 3, "explain": "“Degree of \\( (x^2 + 1)(x^3 - x) \\)” means: \\( 5 \\)"}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:eae5195e', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "If \\( (x - 4) \\) is a factor of \\( \\text{f}(x) \\), then:", "options": ["\\( \\text{f}(0) = 4 \\)", "\\( \\text{f}(4) = 0 \\)", "\\( \\text{f}(-4) = 0 \\)", "\\( \\text{f}(4) = 4 \\)"]}'::jsonb, '{"answer": 1, "explain": "The factor \\( (x-a) \\) means \\( \\text{f}(a)=0 \\); here \\( a=4 \\), so \\( \\text{f}(4)=0 \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:391b1674', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "Which condition shows that \\( (x + 2) \\) is a factor of \\( \\text{f}(x) \\)?", "options": ["\\( \\text{f}(2) = 0 \\)", "\\( \\text{f}(0) = -2 \\)", "\\( \\text{f}(-2) = 0 \\)", "\\( \\text{f}(2) = -2 \\)"]}'::jsonb, '{"answer": 2, "explain": "\\( (x+2)=(x-(-2)) \\), so the matching value is \\( x=-2 \\): \\( \\text{f}(-2)=0 \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:7b99d8cb', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "For \\( \\text{f}(x) = x^3 - 5x^2 + 2x + 8 \\), what is \\( \\text{f}(2) \\)?", "options": ["\\( 16 \\)", "\\( -4 \\)", "\\( 8 \\)", "\\( 0 \\)"]}'::jsonb, '{"answer": 3, "explain": "\\( \\text{f}(2) = 8 - 20 + 4 + 8 = 0 \\), so \\( (x-2) \\) is a factor."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:f16d412a', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "For \\( \\text{f}(x) = x^3 - x^2 - 4x + 4 \\), which is a factor?", "options": ["\\( (x - 1) \\)", "\\( (x + 1) \\)", "\\( (x - 4) \\)", "\\( (x + 4) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\text{f}(1) = 1 - 1 - 4 + 4 = 0 \\), so \\( (x-1) \\) is a factor. \\( \\text{f}(-1)=6\\ne 0 \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:5032d358', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "To test whether \\( (2x + 1) \\) is a factor, evaluate:", "options": ["\\( \\text{f}(\\tfrac{1}{2}) \\)", "\\( \\text{f}(-\\tfrac{1}{2}) \\)", "\\( \\text{f}(2) \\)", "\\( \\text{f}(-2) \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( 2x+1=0 \\Rightarrow x=-\\tfrac{1}{2} \\), so test \\( \\text{f}\\!\\left(-\\tfrac{1}{2}\\right) \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:d5f4dbbf', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "\\( \\text{f}(x) = (x - 1)(x + 2)(2x - 3) \\). The solutions of \\( \\text{f}(x) = 0 \\) are:", "options": ["\\( x = -1,\\ 2,\\ -\\tfrac{3}{2} \\)", "\\( x = 1,\\ -2 \\) only", "\\( x = 1,\\ -2,\\ \\tfrac{3}{2} \\)", "the factorised form is the solution"]}'::jsonb, '{"answer": 2, "explain": "Set each factor to 0: \\( x=1 \\), \\( x=-2 \\), \\( x=\\tfrac{3}{2} \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:381d2111', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "A student writes \\( \\text{f}(x) = (x - 1)(2x^2 + x - 6) \\) and stops. To solve \\( \\text{f}(x) = 0 \\) they must next:", "options": ["factorise the quadratic and set each factor to 0", "divide again by \\( (x - 1) \\)", "substitute \\( x = 0 \\)", "state the remainder"]}'::jsonb, '{"answer": 0, "explain": "Factorise \\( 2x^2+x-6=(2x-3)(x+2) \\), then set every factor to zero."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:eb23c38d', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "\\( x^3 - 3x - 2 \\) has root \\( x = 2 \\); dividing by \\( (x - 2) \\) gives \\( x^2 + 2x + 1 \\). The other roots are:", "options": ["\\( x = 1 \\) and \\( x = -2 \\)", "\\( x = -1 \\) (repeated)", "\\( x = 2 \\) (repeated)", "\\( x = 1 \\) only"]}'::jsonb, '{"answer": 1, "explain": "\\( x^2+2x+1=(x+1)^2=0 \\Rightarrow x=-1 \\), a repeated root."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:6f264d1a', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "For \\( \\text{f}(x) = x^3 + 4x^2 + x - 6 \\), which value is NOT worth testing with the factor theorem?", "options": ["\\( x = 1 \\)", "\\( x = -2 \\)", "\\( x = 5 \\)", "\\( x = 3 \\)"]}'::jsonb, '{"answer": 2, "explain": "Whole-number roots divide the constant \\( 6 \\): \\( \\pm1,\\pm2,\\pm3,\\pm6 \\). \\( 5 \\) is not a divisor of 6."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:5ff5a45d', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "If \\( \\text{f}(a) = 7 \\), what can you conclude?", "options": ["\\( (x - a) \\) is a factor", "\\( (x - a) \\) is not a factor", "the remainder theorem gives the roots", "\\( a \\) is a root"]}'::jsonb, '{"answer": 1, "explain": "The factor theorem needs \\( \\text{f}(a)=0 \\); since \\( \\text{f}(a)=7\\ne 0 \\), \\( (x-a) \\) is not a factor."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:mcq:c8db7701', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'mcq', 'mcq', 1, '{"question": "For \\( 2x^3 - x^2 - 7x + 6 \\), the value of \\( \\text{f}(1) \\) is:", "options": ["\\( 2 \\)", "\\( 6 \\)", "\\( 0 \\)", "\\( -1 \\)"]}'::jsonb, '{"answer": 2, "explain": "\\( \\text{f}(1) = 2 - 1 - 7 + 6 = 0 \\), so \\( (x-1) \\) is a factor."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:tf:c6eaf32e', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'tf', 'tf', 1, '{"question": "If \\( \\text{f}(5) = 0 \\), then \\( (x - 5) \\) is a factor of \\( \\text{f}(x) \\)."}'::jsonb, '{"answer": true, "explain": "This is exactly the factor theorem: \\( \\text{f}(a)=0 \\Rightarrow (x-a) \\) is a factor."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:tf:525c1928', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'tf', 'tf', 1, '{"question": "If \\( (x + 3) \\) is a factor of \\( \\text{f}(x) \\), then \\( \\text{f}(3) = 0 \\)."}'::jsonb, '{"answer": false, "explain": "The factor \\( (x+3)=(x-(-3)) \\) matches \\( x=-3 \\), so it is \\( \\text{f}(-3)=0 \\), not \\( \\text{f}(3) \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:tf:5a062f24', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'tf', 'tf', 1, '{"question": "The remainder theorem is examined on this qualification."}'::jsonb, '{"answer": false, "explain": "The remainder theorem was removed from the 6993 specification in 2018; only the factor theorem is tested."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:tf:8efaa683', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'tf', 'tf', 1, '{"question": "To test whether \\( (3x - 1) \\) is a factor, you evaluate \\( \\text{f}\\!\\left(\\tfrac{1}{3}\\right) \\)."}'::jsonb, '{"answer": true, "explain": "\\( 3x-1=0 \\Rightarrow x=\\tfrac{1}{3} \\), so \\( (3x-1) \\) is a factor when \\( \\text{f}\\!\\left(\\tfrac{1}{3}\\right)=0 \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:tf:69e9242c', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'tf', 'tf', 1, '{"question": "A cubic can have a repeated root, so its ''three roots'' may include the same value more than once."}'::jsonb, '{"answer": true, "explain": "A squared factor like \\( (x+1)^2 \\) contributes the root \\( x=-1 \\) twice, e.g. \\( x^3-3x-2=(x-2)(x+1)^2 \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:tf:d040f3ce', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'tf', 'tf', 1, '{"question": "Once you write \\( \\text{f}(x) = (x-1)(x+2)(2x-3) \\), you have solved \\( \\text{f}(x) = 0 \\)."}'::jsonb, '{"answer": false, "explain": "Factorising is not solving. You must set each factor to zero: \\( x=1,\\ -2,\\ \\tfrac{3}{2} \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:tf:f0b151d5', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'tf', 'tf', 1, '{"question": "In a ''detailed reasoning'' factor-theorem question, writing the three factors from your calculator with no working scores full marks."}'::jsonb, '{"answer": false, "explain": "Answer-only responses score zero on a DR question; you must show \\( \\text{f}(a)=0 \\) and obtain the quadratic factor."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:tf:fb461b0b', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'tf', 'tf', 1, '{"question": "If \\( \\text{f}(2) = 3 \\), then \\( (x - 2) \\) is a factor of \\( \\text{f}(x) \\)."}'::jsonb, '{"answer": false, "explain": "\\( (x-2) \\) is a factor only when \\( \\text{f}(2)=0 \\); here \\( \\text{f}(2)=3 \\), so it is not a factor."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:learn:15335c4d', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'learn', 'mcq', 1, '{"readingTitle": "What is the factor theorem?", "reading": "<p>The <strong>factor theorem</strong> connects a <em>value</em> of a polynomial to one of its <em>factors</em>. For a polynomial \\( \\text{f}(x) \\):</p>\n            <ul>\n              <li>If \\( \\text{f}(a) = 0 \\), then \\( (x - a) \\) is a <strong>factor</strong> of \\( \\text{f}(x) \\).</li>\n              <li>The reverse is also true: if \\( (x - a) \\) is a factor, then \\( \\text{f}(a) = 0 \\).</li>\n              <li>For a factor of the form \\( (bx - a) \\), test \\( \\text{f}\\!\\left(\\tfrac{a}{b}\\right) \\): if it is zero, \\( (bx - a) \\) is a factor. (Set \\( bx - a = 0 \\) to see why: \\( x = \\tfrac{a}{b} \\).)</li>\n            </ul>\n            <p>Watch the <strong>sign</strong>: the factor \\( (x - a) \\) matches the value \\( x = a \\), so \\( (x + 3) \\) is a factor exactly when \\( \\text{f}(-3) = 0 \\).</p>\n            <p><strong>Spec boundary:</strong> the factor theorem is the special case of the <em>remainder theorem</em> where the remainder is zero — but the <strong>remainder theorem was removed from this specification in 2018</strong>, so you are only ever tested on the factor theorem.</p>", "question": "If \\( \\text{f}(3) = 0 \\), which is a factor of \\( \\text{f}(x) \\)?", "options": ["\\( (x+3) \\)", "\\( (x-3) \\)", "\\( 3x \\)", "\\( (x-\\tfrac{1}{3}) \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( \\text{f}(a)=0 \\) gives the factor \\( (x-a) \\); here \\( a=3 \\), so \\( (x-3) \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:learn:5f013d83', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'learn', 'mcq', 1, '{"readingTitle": "How do you find a linear factor of a cubic?", "reading": "<p>A cubic will not always factorise by inspection, so you hunt for a first factor with the factor theorem. The trick is knowing <strong>which values to try</strong>.</p>\n            <ul>\n              <li>Any whole-number root must be a <strong>divisor of the constant term</strong>. For \\( x^3 - 5x^2 + 2x + 8 \\) the constant is \\( 8 \\), so test \\( x = \\pm 1,\\ \\pm 2,\\ \\pm 4,\\ \\pm 8 \\).</li>\n              <li>Substitute each candidate into \\( \\text{f}(x) \\). The moment you get \\( \\text{f}(a) = 0 \\), you have found the factor \\( (x - a) \\) — stop testing.</li>\n              <li>If the leading coefficient is not \\( 1 \\), also try <strong>fractions</strong> \\( \\dfrac{\\text{divisor of the constant}}{\\text{divisor of the leading coefficient}} \\) (see the \\( (bx-a) \\) card).</li>\n            </ul>\n            <p>Start with the small, tidy values \\( \\pm 1, \\pm 2 \\) — examiners design these questions so a low divisor works.</p>", "question": "For \\( \\text{f}(x)=x^3-2x^2-5x+6 \\), which set should you test first?", "options": ["Divisors of 6: \\( \\pm1,\\pm2,\\pm3,\\pm6 \\)", "Only \\( 1 \\) and \\( 2 \\)", "Divisors of 2", "Multiples of 6"]}'::jsonb, '{"answer": 0, "explain": "Whole-number roots divide the constant term, which is 6, so try \\( \\pm1,\\pm2,\\pm3,\\pm6 \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:learn:771fbce0', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'learn', 'mcq', 1, '{"readingTitle": "Worked example: factorise and solve a cubic", "reading": "<p><strong>Solve \\( 2x^3 - x^2 - 7x + 6 = 0 \\).</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Constant term is \\( 6 \\); try small divisors. \\( \\text{f}(1) = 2 - 1 - 7 + 6 = 0 \\), so \\( (x - 1) \\) is a factor.</td></tr>\n              <tr><td>2. Divide (or equate coefficients) to get the quadratic factor: \\( 2x^3 - x^2 - 7x + 6 = (x - 1)(2x^2 + x - 6) \\).</td></tr>\n              <tr><td>3. Factorise the quadratic: \\( 2x^2 + x - 6 = (2x - 3)(x + 2) \\).</td></tr>\n              <tr><td>4. So \\[ 2x^3 - x^2 - 7x + 6 = (x - 1)(2x - 3)(x + 2). \\]</td></tr>\n              <tr><td>5. <strong>Solve:</strong> set each factor to \\( 0 \\): \\( x = 1,\\ x = \\tfrac{3}{2},\\ x = -2 \\).</td></tr>\n            </table>\n            <p>Check one root: \\( \\text{f}(-2) = 2(-8) - 4 + 14 + 6 = 0 \\). ✓ Finding the factors is only <em>half</em> the job — the question said \"solve\", so you must give the three \\( x \\)-values.</p>", "question": "The solutions of \\( 2x^3 - x^2 - 7x + 6 = 0 \\) are:", "options": ["\\( x=1,\\ \\tfrac{3}{2},\\ -2 \\)", "\\( x=-1,\\ -\\tfrac{3}{2},\\ 2 \\)", "\\( x=1,\\ 2,\\ 3 \\)", "\\( x=1,\\ -2 \\) only"]}'::jsonb, '{"answer": 0, "explain": "From \\( (x-1)(2x-3)(x+2)=0 \\): \\( x=1,\\ \\tfrac{3}{2},\\ -2 \\) — all three roots."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:learn:17394dfc', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'learn', 'mcq', 1, '{"readingTitle": "How do you test for a factor like (2x − 3)?", "reading": "<p>When the leading coefficient is not \\( 1 \\), some factors are <strong>non-monic</strong>, such as \\( (2x - 3) \\). To test one, use the \\( (bx - a) \\) rule: evaluate \\( \\text{f}\\!\\left(\\tfrac{a}{b}\\right) \\).</p>\n            <ul>\n              <li>\\( (2x - 3) \\) is a factor when \\( \\text{f}\\!\\left(\\tfrac{3}{2}\\right) = 0 \\), because \\( 2x - 3 = 0 \\Rightarrow x = \\tfrac{3}{2} \\).</li>\n              <li>\\( (3x + 1) \\) is a factor when \\( \\text{f}\\!\\left(-\\tfrac{1}{3}\\right) = 0 \\).</li>\n            </ul>\n            <p><strong>Check for the last worked example:</strong> \\( \\text{f}\\!\\left(\\tfrac{3}{2}\\right) = 2\\left(\\tfrac{27}{8}\\right) - \\tfrac{9}{4} - \\tfrac{21}{2} + 6 = 0 \\), confirming \\( (2x - 3) \\) is a factor.</p>\n            <p>In practice you rarely need this on a cubic — one whole-number factor usually appears first, and then a quadratic (which you factorise normally) takes care of the non-monic factor.</p>", "question": "To test whether \\( (3x - 2) \\) is a factor, evaluate:", "options": ["\\( \\text{f}(\\tfrac{3}{2}) \\)", "\\( \\text{f}(\\tfrac{2}{3}) \\)", "\\( \\text{f}(-\\tfrac{2}{3}) \\)", "\\( \\text{f}(3) \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( 3x-2=0 \\Rightarrow x=\\tfrac{2}{3} \\), so test \\( \\text{f}\\!\\left(\\tfrac{2}{3}\\right) \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:learn:0dd69aba', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the quadratic factor?", "reading": "<p>Once you have one linear factor \\( (x - a) \\), the cubic is \\( (x - a) \\times (\\text{a quadratic}) \\). Two reliable ways to find that quadratic:</p>\n            <ul>\n              <li><strong>Algebraic long division</strong> — divide the cubic by \\( (x - a) \\); the quotient is the quadratic (covered in lesson 2.1).</li>\n              <li><strong>Equating coefficients</strong> — write \\( \\text{f}(x) = (x - a)(px^2 + qx + r) \\), expand, and match the coefficients of each power of \\( x \\).</li>\n            </ul>\n            <p><strong>Worked example — \\( x^3 - x^2 - 4x + 4 \\), given \\( (x - 1) \\) is a factor:</strong> write \\( (x - 1)(x^2 + bx - 4) \\). The constant \\( -1 \\times (-4) = 4 \\) ✓. Matching the \\( x^2 \\) term: \\( b - 1 = -1 \\Rightarrow b = 0 \\). So \\( \\text{f}(x) = (x - 1)(x^2 - 4) = (x - 1)(x - 2)(x + 2) \\).</p>", "question": "\\( 2x^3 - x^2 - 7x + 6 = (x - 1)(2x^2 + bx - 6) \\). What is \\( b \\)?", "options": ["\\( b = 1 \\)", "\\( b = -1 \\)", "\\( b = 2 \\)", "\\( b = -6 \\)"]}'::jsonb, '{"answer": 0, "explain": "Matching the \\( x^2 \\) coefficient: \\( b - 2 = -1 \\Rightarrow b = 1 \\); the \\( x \\) term \\( -6 - b = -7 \\) confirms \\( b = 1 \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:learn:ab0713a8', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'learn', 'mcq', 1, '{"readingTitle": "What does ''detailed reasoning'' demand here?", "reading": "<p>Factor-theorem cubics are a favourite <strong>\"detailed reasoning\" (DR)</strong> question. The DR instruction means <em>every analytical step must be visible</em> — a calculator may be used, but an answer read straight off it earns nothing.</p>\n            <ul>\n              <li>You must <strong>show \\( \\text{f}(a) = 0 \\)</strong> for your trial value — this proves you used the factor theorem.</li>\n              <li>You must then <strong>obtain the quadratic factor</strong> before stating the three linear factors (or apply the factor theorem to at least two values).</li>\n              <li>Writing the factorisation \\( (x + 1)(x - 2)(x - 4) \\) with <em>no working</em> scores <strong>zero</strong> on a DR question, even if it is correct.</li>\n            </ul>\n            <p>And remember: a factorised cubic is <strong>not yet solved</strong>. \"Solve \\( \\text{f}(x) = 0 \\)\" needs each factor set to zero and the \\( x \\)-values written down.</p>", "question": "In a DR factor-theorem question, what must be visible?", "options": ["\\( \\text{f}(a)=0 \\) for a trial value, and the quadratic factor", "only the three final factors", "just the calculator answer", "the value of the discriminant"]}'::jsonb, '{"answer": 0, "explain": "DR requires the factor-theorem step \\( \\text{f}(a)=0 \\) to be shown and the quadratic factor obtained."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:misc:f3325f82', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> To check the factor \\( (x - 2) \\), a student evaluates \\( \\text{f}(-2) \\).</p><p><strong>✅ The correct idea:</strong> \\( (x - a) \\) is a factor when \\( \\text{f}(a) = 0 \\), so \\( (x-2) \\) needs \\( \\text{f}(2) \\), not \\( \\text{f}(-2) \\). The value you substitute is the OPPOSITE sign to the number in the bracket.</p>", "question": "\\( (x - 2) \\) is a factor. Which must be zero?", "options": ["\\( \\text{f}(2) \\)", "\\( \\text{f}(-2) \\)", "\\( \\text{f}(0) \\)", "\\( \\text{f}(\\tfrac{1}{2}) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x-2) \\) matches \\( x=2 \\), so \\( \\text{f}(2)=0 \\)."}'::jsonb),
('additional-maths:2-2-the-factor-theorem-and-cubics:misc:817a835a', 'additional-maths', 'additional-maths:2-2-the-factor-theorem-and-cubics', '2.2 The Factor Theorem and Cubics', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing \\( \\text{f}(x) = (x-1)(2x-3)(x+2) \\) and stopping when asked to SOLVE \\( \\text{f}(x) = 0 \\).</p><p><strong>✅ The correct idea:</strong> Factorising is not solving. A weak answer leaves the brackets; a strong answer sets each factor to zero to give \\( x = 1,\\ \\tfrac{3}{2},\\ -2 \\).</p>", "question": "Solve \\( (x-1)(2x-3)(x+2) = 0 \\).", "options": ["\\( x = 1,\\ \\tfrac{3}{2},\\ -2 \\)", "\\( x = 1,\\ 3,\\ 2 \\)", "\\( x = -1,\\ \\tfrac{3}{2},\\ 2 \\)", "leave as factors"]}'::jsonb, '{"answer": 0, "explain": "Each factor set to zero gives \\( x=1,\\ \\tfrac{3}{2},\\ -2 \\)."}'::jsonb)
